class ImageProcessingError(Exception):
    """Custom exception for image processing failures."""
    pass


class S3Helper:
    """Helper class for S3 operations."""

    def __init__(self, client):
        self.client = client

    def read_object(self, bucket, key):
        """Read an object from S3 and return its body and metadata."""
        logger.info(f"Reading object from s3://{bucket}/{key}")
        try:
            response = self.client.get_object(Bucket=bucket, Key=key)
            body = response["Body"].read()
            metadata = response.get("Metadata", {})
            content_type = response.get("ContentType", "")
            content_length = response.get("ContentLength", 0)

            logger.info(
                f"Successfully read object: size={content_length} bytes, "
                f"content_type={content_type}"
            )

            return {
                "body": body,
                "metadata": metadata,
                "content_type": content_type,
                "content_length": content_length,
            }
        except self.client.exceptions.NoSuchKey:
            logger.error(f"Object not found: s3://{bucket}/{key}")
            raise ImageProcessingError(f"Object not found: s3://{bucket}/{key}")
        except Exception as e:
            logger.error(f"Error reading from S3: {str(e)}")
            raise

    def write_object(self, bucket, key, body, content_type="application/json", metadata=None):
        """Write an object to S3."""
        logger.info(f"Writing object to s3://{bucket}/{key}")
        try:
            put_params = {
                "Bucket": bucket,
                "Key": key,
                "Body": body,
                "ContentType": content_type,
            }
            if metadata:
                put_params["Metadata"] = metadata

            self.client.put_object(**put_params)
            logger.info(f"Successfully wrote object to s3://{bucket}/{key}")
        except Exception as e:
            logger.error(f"Error writing to S3: {str(e)}")
            raise

    def write_json(self, bucket, key, data, metadata=None):
        """Write a JSON object to S3."""
        json_body = json.dumps(data, indent=2, default=str)
        self.write_object(
            bucket, key, json_body.encode("utf-8"),
            content_type="application/json",
            metadata=metadata,
        )

    def get_object_tags(self, bucket, key):
        """Get tags for an S3 object."""
        try:
            response = self.client.get_object_tagging(Bucket=bucket, Key=key)
            return {tag["Key"]: tag["Value"] for tag in response.get("TagSet", [])}
        except Exception as e:
            logger.warning(f"Could not get tags for s3://{bucket}/{key}: {str(e)}")
            return {}

    def set_object_tags(self, bucket, key, tags):
        """Set tags on an S3 object."""
        try:
            tag_set = [{"Key": k, "Value": v} for k, v in tags.items()]
            self.client.put_object_tagging(
                Bucket=bucket,
                Key=key,
                Tagging={"TagSet": tag_set},
            )
            logger.info(f"Set tags on s3://{bucket}/{key}: {tags}")
        except Exception as e:
            logger.warning(f"Could not set tags for s3://{bucket}/{key}: {str(e)}")


class NotificationHelper:
    """Helper class for SNS notifications."""

    def __init__(self, client, topic_arn):
        self.client = client
        self.topic_arn = topic_arn

    def send_notification(self, subject, message, attributes=None):
        """Send an SNS notification."""
        if not self.topic_arn:
            logger.warning("SNS_TOPIC_ARN not configured, skipping notification")
            return None

        logger.info(f"Sending SNS notification: {subject}")
        try:
            params = {
                "TopicArn": self.topic_arn,
                "Subject": subject[:100],  # SNS subject limit
                "Message": message,
            }
            if attributes:
                params["MessageAttributes"] = {
                    k: {"DataType": "String", "StringValue": str(v)}
                    for k, v in attributes.items()
                }

            response = self.client.publish(**params)
            message_id = response.get("MessageId")
            logger.info(f"SNS notification sent, MessageId: {message_id}")
            return message_id
        except Exception as e:
            logger.error(f"Error sending SNS notification: {str(e)}")
            # Don't raise - notifications are non-critical
            return None

    def send_success_notification(self, source_bucket, source_key, results_key, processing_details):
        """Send a success notification."""
        message = json.dumps(
            {
                "status": "SUCCESS",
                "source": f"s3://{source_bucket}/{source_key}",
                "results": f"s3://{RESULTS_BUCKET}/{results_key}",
                "details": processing_details,
                "timestamp": datetime.utcnow().isoformat(),
            },
            indent=2,
            default=str,
        )
        return self.send_notification(
            subject=f"Image Processed: {source_key}",
            message=message,
            attributes={"status": "SUCCESS", "source_key": source_key},
        )

    def send_failure_notification(self, source_bucket, source_key, error_message):
        """Send a failure notification."""
        message = json.dumps(
            {
                "status": "FAILURE",
                "source": f"s3://{source_bucket}/{source_key}",
                "error": error_message,
                "timestamp": datetime.utcnow().isoformat(),
            },
            indent=2,
            default=str,
        )
        return self.send_notification(
            subject=f"Image Processing Failed: {source_key}",
            message=message,
            attributes={"status": "FAILURE", "source_key": source_key},
        )


class MetricsHelper:
    """Helper class for CloudWatch custom metrics."""

    def __init__(self, client, namespace="ImageProcessor"):
        self.client = client
        self.namespace = namespace

    def put_metric(self, metric_name, value, unit="Count", dimensions=None):
        """Put a custom metric to CloudWatch."""
        try:
            metric_data = {
                "MetricName": metric_name,
                "Value": value,
                "Unit": unit,
                "Timestamp": datetime.utcnow(),
            }
            if dimensions:
                metric_data["Dimensions"] = [
                    {"Name": k, "Value": v} for k, v in dimensions.items()
                ]

            self.client.put_metric_data(
                Namespace=self.namespace,
                MetricData=[metric_data],
            )
        except Exception as e:
            logger.warning(f"Could not put metric {metric_name}: {str(e)}")

    def record_processing_time(self, duration_ms, image_format):
        """Record image processing duration."""
        self.put_metric(
            "ProcessingDuration",
            duration_ms,
            unit="Milliseconds",
            dimensions={"ImageFormat": image_format},
        )

    def record_image_size(self, size_bytes, image_format):
        """Record image size."""
        self.put_metric(
            "ImageSize",
            size_bytes,
            unit="Bytes",
            dimensions={"ImageFormat": image_format},
        )

    def record_success(self):
        """Record a successful processing."""
        self.put_metric("ProcessingSuccess", 1)

    def record_failure(self, error_type="Unknown"):
        """Record a failed processing."""
        self.put_metric(
            "ProcessingFailure",
            1,
            dimensions={"ErrorType": error_type},
        )


def validate_image_key(key):
    """Validate that the S3 key refers to a supported image format."""
    key_lower = key.lower()
    for fmt in SUPPORTED_FORMATS:
        if key_lower.endswith(fmt):
            return fmt
    return None


